/* atan, n = 3, r = 22: 3 levels, widths [2, 2, 1] */
static void
_fixed_atan_series_3(nn_ptr res, nn_srcptr x)
{
    ulong z[3], V[3], T[3], P[3], Z[2];
    ulong v, w1, w0, h, l;
    slong i;

    (void) v; (void) w1; (void) w0; (void) h; (void) l;
    (void) i; (void) Z; (void) V; (void) T; (void) P;

    flint_mpn_sqrhigh(z, x, 3);

    v = UWORD(0x2492492492492492);

    /* V_1 = c - z V_2   (2 x 1 limbs) */
    _fixed_mulhi_2x1(&h, &l, z[2], z[1], v);
    sub_ddmmss(w1, w0, UWORD(0x3333333333333333), UWORD(0x3333333333333333), h, l);

    /* V_0 = c - z V_1   (2 x 2 limbs) */
    _fixed_mulhi_2x2_sloppy(&h, &l, z[2], z[1], w1, w0);
    sub_ddmmss(w1, w0, UWORD(0x5555555555555555), UWORD(0x5555555555555555), h, l);

    /* atan = x - x^3 V_0 */
    P[0] = UWORD(0);
    P[1] = w0; P[2] = w1;
    flint_mpn_mulhigh_n(T, z, x, 3);
    flint_mpn_mulhigh_n(V, T, P, 3);
    NN_SUB_3(res, x, V);
}

void
fixed_atan_opt_3(nn_ptr res, nn_srcptr x)
{
    const int r = 22;
    ulong x0, x1, x2;
    ulong y0, y1, y2;
    ulong a0, a1, a2;
    ulong e0, e1, e2;
    ulong v0, v1, v2;
    ulong w0, w1, w2;
    ulong bw, m, h, lt;
    ulong S[4], nd[6], t[3], q[3];
    slong i, nc;
    int nz;


    nn_srcptr tab;
    tab = _fixed_atans_tab(3, r, &nc);

    x0 = 0;
    x1 = 0;
    x2 = 0;
    y0 = x[0];
    y1 = x[1];
    y2 = x[2];
    a0 = 0;
    a1 = 0;
    a2 = 0;

#define AP(ii) (tab + (ii) * nc + (nc - 3))

    /* window 0 */
    {
        nn_srcptr Ap;

        /* boundary step i = 1 */
        Ap = AP(1);
        v0 = MPN_RIGHT_SHIFT_LOW(x1, x0, 1);
        v1 = MPN_RIGHT_SHIFT_LOW(x2, x1, 1);
        v2 = MPN_RIGHT_SHIFT_LOW(UWORD(1), x2, 1);
        w0 = MPN_RIGHT_SHIFT_LOW(y1, y0, 1);
        w1 = MPN_RIGHT_SHIFT_LOW(y2, y1, 1);
        w2 = MPN_RIGHT_SHIFT_LOW(UWORD(0), y2, 1);
        sub_ddddmmmmssss(bw, e2, e1, e0,
            UWORD(0), y2, y1, y0,
            UWORD(0), v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        add_sssaaaaaa(x2, x1, x0,
            x2, x1, x0,
            (w2) & m, (w1) & m, (w0) & m);
        add_sssaaaaaa(a2, a1, a0,
            a2, a1, a0,
            Ap[2] & m, Ap[1] & m, Ap[0] & m);
        y0 = (y0 & bw) | (e0 & m);
        y1 = (y1 & bw) | (e1 & m);
        y2 = (y2 & bw) | (e2 & m);

        h = y2;

        for (i = 2; i <= 22; i++)
        {
            int b = (int) (i - 0);

            lt = MPN_RIGHT_SHIFT_LOW(UWORD(1), x2, b);
            if (h < lt)
                continue;    /* certain reject */

            Ap = AP(i);
            v0 = MPN_RIGHT_SHIFT_LOW(x1, x0, b);
            v1 = MPN_RIGHT_SHIFT_LOW(x2, x1, b);
            v2 = lt;
            w0 = MPN_RIGHT_SHIFT_LOW(y1, y0, b);
            w1 = MPN_RIGHT_SHIFT_LOW(y2, y1, b);
            w2 = MPN_RIGHT_SHIFT_LOW(UWORD(0), y2, b);
            sub_ddddmmmmssss(bw, e2, e1, e0,
                UWORD(0), y2, y1, y0,
                UWORD(0), v2, v1, v0);
            m = ~bw;                /* accept iff no borrow */
            add_sssaaaaaa(x2, x1, x0,
                x2, x1, x0,
                (w2) & m, (w1) & m, (w0) & m);
            add_sssaaaaaa(a2, a1, a0,
                a2, a1, a0,
                Ap[2] & m, Ap[1] & m, Ap[0] & m);
            y0 = (y0 & bw) | (e0 & m);
            y1 = (y1 & bw) | (e1 & m);
            y2 = (y2 & bw) | (e2 & m);
            h = y2;
        }
    }

    /* the step at i = r restores Y < trunc(X >> r) <= X 2^-r;
       entering it Y < X 2^-(r-1), so two passes suffice */
    for (nz = 0; nz < 2; nz++)
    {
        nn_srcptr Ap = AP((slong) r);
        const int b = 22;

        lt = MPN_RIGHT_SHIFT_LOW(UWORD(1), x2, b);
        v0 = MPN_RIGHT_SHIFT_LOW(x1, x0, b);
        v1 = MPN_RIGHT_SHIFT_LOW(x2, x1, b);
        v2 = lt;
        w0 = MPN_RIGHT_SHIFT_LOW(y1, y0, b);
        w1 = MPN_RIGHT_SHIFT_LOW(y2, y1, b);
        w2 = MPN_RIGHT_SHIFT_LOW(UWORD(0), y2, b);
        sub_ddddmmmmssss(bw, e2, e1, e0,
            UWORD(0), y2, y1, y0,
            UWORD(0), v2, v1, v0);
        m = ~bw;                /* accept iff no borrow */
        add_sssaaaaaa(x2, x1, x0,
            x2, x1, x0,
            (w2) & m, (w1) & m, (w0) & m);
        add_sssaaaaaa(a2, a1, a0,
            a2, a1, a0,
            Ap[2] & m, Ap[1] & m, Ap[0] & m);
        y0 = (y0 & bw) | (e0 & m);
        y1 = (y1 & bw) | (e1 & m);
        y2 = (y2 & bw) | (e2 & m);
    }

#undef AP

    /* t = Y 2^(FLINT_BITS 3) / X */
    S[0] = x0;
    S[1] = x1;
    S[2] = x2;
    S[3] = 1;
    nz = (y0 != 0) | (y1 != 0) | (y2 != 0);
    if (nz)
    {
        nd[0] = 0;
        nd[1] = 0;
        nd[2] = 0;
        nd[3] = y0;
        nd[4] = y1;
        nd[5] = y2;
        mpn_tdiv_qr(t, nd, 0, nd, 6, S, 4);
    }
    else
    {
        t[0] = 0;
        t[1] = 0;
        t[2] = 0;
    }

    _fixed_atan_series_3(q, t);

    add_sssaaaaaa(a2, a1, a0,
        a2, a1, a0,
        q[2], q[1], q[0]);
    res[0] = a0;
    res[1] = a1;
    res[2] = a2;
}


#endif /* FLINT_BITS == 64 */
